#!/usr/bin/env node
// Sync canonical commons solution YAMLs into a generated TS module.
//
// The RN example previously embedded VOICE_AGENT_YAML and RAG_YAML as inline
// string constants in src/screens/SolutionsScreen.tsx because the placeholder
// model IDs shipped in sdk/runanywhere-commons/examples/solutions/*.yaml did
// not match what App.tsx seeds. Those IDs were later aligned, so the inline
// copy is now byte-equivalent to the commons source.
//
// This script reads the canonical commons YAMLs and emits
// src/generated/solutionsYaml.ts. Run via postinstall, prepended to the
// typecheck script, and on demand:
//
//   node scripts/sync-solutions-yamls.js
//
// Editing the generated file is forbidden; modify the commons YAMLs instead.

const fs = require('node:fs');
const path = require('node:path');

const REPO_ROOT = path.resolve(__dirname, '../../../../');
const COMMONS_SOLUTIONS_DIR = path.join(
  REPO_ROOT,
  'sdk/runanywhere-commons/examples/solutions'
);
const OUTPUT_FILE = path.resolve(
  __dirname,
  '../src/generated/solutionsYaml.ts'
);

function readYaml(name) {
  const filePath = path.join(COMMONS_SOLUTIONS_DIR, name);
  if (!fs.existsSync(filePath)) {
    throw new Error(`Commons solution YAML not found: ${filePath}`);
  }
  return fs.readFileSync(filePath, 'utf8');
}

function emitConst(varName, sourceFile, content) {
  // Encode as a single-line JSON string so TS sees a string literal regardless
  // of YAML's whitespace/escape rules — JSON.stringify handles quotes,
  // newlines, and unicode without any hand-rolled escaping.
  return `// Sourced from sdk/runanywhere-commons/examples/solutions/${sourceFile}\nexport const ${varName} = ${JSON.stringify(content)};\n`;
}

function main() {
  const voiceAgent = readYaml('voice_agent.yaml');
  const rag = readYaml('rag.yaml');

  const banner = `// AUTO-GENERATED by examples/react-native/RunAnywhereAI/scripts/sync-solutions-yamls.js\n// Do not edit by hand. Source of truth: sdk/runanywhere-commons/examples/solutions/*.yaml\n// Regenerate via \`node scripts/sync-solutions-yamls.js\`.\n\n`;
  const body =
    emitConst('VOICE_AGENT_YAML', 'voice_agent.yaml', voiceAgent) +
    '\n' +
    emitConst('RAG_YAML', 'rag.yaml', rag);

  fs.mkdirSync(path.dirname(OUTPUT_FILE), { recursive: true });
  fs.writeFileSync(OUTPUT_FILE, banner + body, 'utf8');
  process.stdout.write(
    `[sync-solutions-yamls] wrote ${path.relative(REPO_ROOT, OUTPUT_FILE)}\n`
  );
}

main();
